// 1. ống dựng một đối tượng để lưu trữ các tham số cấu hình
public class AppSettings
{
    public string DatabaseConnection { get; set; }
    public string ApiKey { get; set; }
    public string SecretKey { get; set; }
    public int MaxRetries { get; set; }
    public int Timeout { get; set; }
}

// 2. Phương thức để đọc các tham số từ file cấu hình
public static AppSettings LoadSettings(string filePath)
{
    // Đọc file JSON
    var json = File.ReadAllText(filePath);
    // Chuyển đổi JSON sang đối tượng AppSettings
    var settings = JsonConvert.DeserializeObject<AppSettings>(json);
    return settings;
}

// 3. Phương thức để lưu các tham số vào file cấu hình
public static void SaveSettings(AppSettings settings, string filePath)
{
    // Chuyển đổi đối tượng AppSettings sang JSON
    var json = JsonConvert.SerializeObject(settings, Formatting.Indented);
    // Ghi vào file
    File.WriteAllText(filePath, json);
}

// 4. Phương thức để lấy giá trị của một tham số cụ thể
public static string GetSettingValue(string key)
{
